#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 5e5+5;
int n,m,Q,cnt;
int Fa[N],dep[N];
int ln[N],rn[N],dfncnt;
int sz[N],wc[N],top[N];
int Ls[N],lscnt;
int tr[N],ans[N];
vector<int> g[N];
struct node{
    int opt,y,l,r,k,id;
}q[N],q1[N],q2[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    ln[u]=(++dfncnt);
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }rn[u]=dfncnt;return;
}
void DFS2(int u,int Top){
    top[u]=Top;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
int Getsonz(int u,int v){
    while(top[u]!=top[v]){
        if(Fa[top[u]]==v)return top[u];
        u=Fa[top[u]];
    }return wc[v];
}
bool cmp(node d1,node d2){
    if(d1.y!=d2.y)return d1.y<d2.y;
    else return d1.opt<d2.opt;
}
void upd(int x,int k){while(x<=n)tr[x]+=k,x+=x&-x;return;}
int ask(int x){int sum=0;while(x)sum+=tr[x],x-=x&-x;return sum;}
void solve(int l,int r,int L,int R){
    if(L>R)return;
    if(l==r){
        for(int i=L;i<=R;i++)
            if(q[i].opt)ans[q[i].id]=Ls[l];
        return;
    }
    int mid=(l+r)>>1,p1=0,p2=0;
    for(int i=L;i<=R;i++)
        if(!q[i].opt){
            if(q[i].k<=mid)
                upd(q[i].l,q[i].id),
                upd(q[i].r+1,-q[i].id),
                q1[++p1]=q[i];
            else q2[++p2]=q[i];
        }else{
            int res=ask(q[i].l);
            if(res>=q[i].k)q1[++p1]=q[i];
            else q[i].k-=res,q2[++p2]=q[i];
        }
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read(),Q=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS1(1,1);DFS2(1,1);
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        int k=read();Ls[i]=k;
        if(ln[x]>ln[y])swap(x,y);
        if(rn[x]>=rn[y]){
            x=Getsonz(y,x);
            if(ln[x]>1)
                q[++cnt]={0,ln[y],1,ln[x]-1,k,1},
                q[++cnt]={0,rn[y]+1,1,ln[x]-1,k,-1};
            if(rn[x]<n)
                q[++cnt]={0,rn[x]+1,ln[y],rn[y],k,1},
                q[++cnt]={0,n+1,ln[y],rn[y],k,-1};
        }else{
            q[++cnt]={0,ln[y],ln[x],rn[x],k,1},
            q[++cnt]={0,rn[y]+1,ln[x],rn[x],k,-1};
        }
    }sort(Ls+1,Ls+m+1);
    lscnt=unique(Ls+1,Ls+m+1)-Ls-1;
    for(int i=1;i<=cnt;i++)
        q[i].k=lower_bound(Ls+1,Ls+lscnt+1,q[i].k)-Ls;
    for(int i=1;i<=Q;i++){
        int x=read(),y=read(),k=read();
        if(ln[x]>ln[y])swap(x,y);
        q[++cnt]={1,ln[y],ln[x],0,k,i};
    }sort(q+1,q+cnt+1,cmp);
    solve(1,lscnt,1,cnt);
    for(int i=1;i<=Q;i++)cout<<ans[i]<<"\n";
    return 0;
}
